#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long floors, entrances, doors_per_floor;
    cin >> floors >> entrances >> doors_per_floor;

    long long apt;
    cin >> apt;

    // Total apartments per entrance
    long long per_entrance = floors * doors_per_floor;

    // Entrance number (1-based)
    long long entrance = (apt - 1) / per_entrance + 1;

    // Position within the entrance (1-based)
    long long pos_in_entrance = (apt - 1) % per_entrance + 1;

    // Floor number (1-based)
    long long floor = (pos_in_entrance - 1) / doors_per_floor + 1;

    // Door number on that floor (1-based)
    long long door = (pos_in_entrance - 1) % doors_per_floor + 1;

    cout << entrance << " " << floor << " " << door << "\n";

    return 0;
}
